//
import { Registry } from '../core/zc-registry';
import { invokeFunction, arrayIncludes, defined, isArray, isString, getPropVal, isObject } from '../utils/zcutils';
import { createElement } from '../utils/zcsvgutils';
import { paintDom, paintDomByConfig } from './dom-paint';
import { animeDom } from './dom-animation';
import { markToNode } from './helper/mark-node-mapping';
import { exportMark } from './helper/mark-as';
import { scanMark } from './mark-scanner';
import { renderDependencies, getParent } from './dom-dependency';
import { STORED_DATA_PATTERN } from '../core/main-zc-init';
import { bindMarkEvents } from './mark-event-binder';

function renderDom(root, parent, tokens) {
    let cache = scanMark(root);

        cache.__tokens__ = tokens;
    return _renderDom(root, parent, cache);
}

function _renderDom(root, _parent, cache) {
    if (!root) { return };
    if (isArray(root)) {    //* Handle array of objects cases
        root.forEach(children => { _renderDom(children, _parent, cache) });
        return;
    }
    let { mark, data = [1], selector = '', order, children, name, dependency, dataAccessor, on = {} } = root,
        parent = getParent(root, _parent),
        markType = markToNode(mark),
        { exclude = [] } = cache,
        // Events
        onStart = on.start || root.onStart,
        onEnd = on.end || root.onEnd;

    if (defined(name) && exclude.length && arrayIncludes(exclude, name)) {
        return;
    }
    let matches = STORED_DATA_PATTERN.exec(data);
    //Handling data as regex like "{{pie_data}}"
    if(isString(data)){
        if(matches && matches[1]){
            data = getPropVal(cache.__tokens__.processedData, matches[1]);
        }
    }else if(matches && matches[1]){
        if(isArray(data)){
            data = data.map(d=>{
                return getPropVal(cache.__tokens__.processedData, matches[1]);
            })
        }
    }
    //Handling array of data as regex like ["{{pie_data}}"], But still need to handle for array of arrays
    
    if (root._rendered) {
        let n = root.element.node();
        let _p = n.parentNode;

        _p.removeChild(n);
        parent.node().appendChild(n);
        delete root._rendered;
        return;
    }

    let selectionObj = createElement(markType, selector, data, parent, order, dataAccessor, { enter_update_exit: true, remove: false }),
        { update: updateSelection, exit: exitSelection } = selectionObj,
        ele = updateSelection;

    if (root.accessor) {
        ele.each(function (d, i) {
            root.accessor.call(this, d, i);
        });
        return;
    }

    if (root.depends) {
        ele = updateSelection = selectionObj.update = parent.select(markType + selector);
    }

    updateSelection.each(initCache);
    exitSelection.each(initCache);

    // onStart callback
    invokeFunction(onStart, ele);

    // Dependencies
    renderDependencies(dependency, parent, cache);

    addProperties.call(ele, root.properties?.props);

    // Paint by properties
    _paintDomByProps(selectionObj, root);

    // Paint by config
    _paintDomByConfig(selectionObj, root, cache, parent);

    //paintbycss

    root.element = ele;

    root.getElement = () => ele;

    // Animation
    if (root.anime) {
        _animeDom(selectionObj, root, cache);
    } else {
        exitSelection.remove().exit(); // Remove exit nodes
    }

    if (root.element) {
        root.element._zc = true; // ZC3271
    }

    if(root.events){
        bindMarkEvents(ele, root.events, cache);
    }

    let fullSelection = parent.selectAll(markType + selector),
        isInnerHTML = root.config && root.config.html;
    if (children && children.length) {
        children.forEach((_) => _renderDom(_, fullSelection, cache));
        fullSelection = null;   //* memory leak fix
    } 
    else if(!isInnerHTML){ // TODO: add a condition to remove only if it has children
        ele.selectAll('*').remove().exit();
        //reason : in some cases - for example DEMOEVENTS_HEATMAP_4
        //when first event triggered - .zc-band-brush component will have children in it
        //but inorder to calculate its transform,its bbox needed,if children there inside it, it was not proper
    }

    // onEnd callback
    invokeFunction(onEnd, ele);

    // Mark as
    exportMark(root, cache);

    if(!root.as){
        delete root.element;
    }

    return ele;
}

function _paintDomByConfig(selection, root, cache, parent) {
    let { mark, config = {} } = root,
        paintOptions = { cache, parser: root },
        { enter: enterConfig, update: updateConfig, exit: exitConfig } = config,
        { enter: enterSelection, update: updateSelection, exit: exitSelection } = selection;

    updateConfig = { ...config, ...updateConfig };
    ['enter', 'update', 'exit'].forEach((_) => delete updateConfig[_]);

    paintDomByConfig({ mark, config: enterConfig }, enterSelection, paintOptions, null, parent);
    paintDomByConfig({ mark, config: updateConfig }, updateSelection, paintOptions, null, parent);
    paintDomByConfig({ mark, config: exitConfig }, exitSelection, paintOptions, null, parent);
}

function _paintDomByProps(selection, root) {
    let { properties = {} } = root,
        { enter: enterProps, update: updateProps, exit: exitProps } = properties,
        { enter: enterSelection, update: updateSelection, exit: exitSelection } = selection;

    updateProps = { ...properties, ...updateProps };
    ['enter', 'update', 'exit'].forEach((_) => delete updateProps[_]);

    paintDom.call(root, enterProps, enterSelection);
    paintDom.call(root, updateProps, updateSelection);
    paintDom.call(root, exitProps, exitSelection);
}

function _animeDom(selection, root, cache) {
    let { mark, anime } = root;

    if (!anime) {
        return;
    }

    let { enter: enterConfig, update: updateConfig, exit: exitConfig } = anime,
        { enter: enterSelection, update: updateSelection, exit: exitSelection } = selection;

    if (!isArray(updateConfig)) {
        updateConfig = { ...anime, ...updateConfig };
        ['enter', 'update', 'exit'].forEach((_) => delete updateConfig[_]);
    }

    animeDom(enterConfig, anime, enterSelection, cache, mark, null, root);
    animeDom(updateConfig, anime, updateSelection, cache, mark, null, root);
    animeDom(exitConfig, anime, exitSelection, cache, mark, () => exitSelection.remove(), root);
}

function initCache() {
    let node = this;
    node.zc_cache = node.zc_cache || {};
}

function addProperties(properties) {
    this.properties(properties);
}

export { renderDom, _renderDom };
Registry.setComponent('mark.render', renderDom);
